//Complexity: O(n^6/w) per sample.
#include<bits/stdc++.h>
using namespace std;
#include "../integer-complexity-128/utils.h"
#include "../integer-complexity-128/statistics.h"
#include "Int1.h"

typedef unsigned long long ull;
const int mod[]={2,3,5,7,11};
//const int N1=21,N2=21,N3=8,N4=6,N5=5;
const int N1=210,N2=210,N3=28,N4=16,N5=5;
//const int N1=315,N2=315,N3=42,N4=24,N5=7;
//const int N1=430,N2=430,N3=58,N4=34,N5=12;
const int _N1=N1+50,_N2=N2+50,_N3=N3+20,_N4=N4+20,_N5=N5+8;
const int M=10,L=N1+N2+N3+N4+N5,D=50;
const int f0[]={0,1,2,3,4,5,5,6,6,6,7,8,7,8,8,8,8,9,8,9,9,9,10,10,9,10,10,9,10,11,10,11,10,11,11}; //f(n)
auto f=new int[_N1][_N2][_N3][_N4][_N5];
auto from=new char[_N1][_N2][_N3][_N4][_N5];
int a[L*M+1],b[L*M+1];
int n1,n2,n3,n4,n5,p,fp,q,fq,r,fr;  //base=2^n1*3^n2*p^n3*q^n4*r^n5.
inline void upd(int &x,int y,char &from,char v){if (y<x)x=y,from=v;}
Int rand_Int(int n){  //rand Int with n digits
	Int x=0;
	for (int i=0;i<n;++i)x=x*10+rand64()%10;
	return x;
}
int calc(Int x,int n1,int n2,int n3,int n4,int n5){
	printf("calc %d %d %d %d %d\n",n1,n2,n3,n4,n5);
	if (n1+2>=_N1 || n2+2>=_N2 || n3+2>=_N3 || n4+2>=_N4 || n5+2>=_N5){
		puts("err");
		return -1;
	}
	for (int i=0;i<=n1;++i)
		for (int j=0;j<=n2;++j)
			for (int k=0;k<=n3;++k)
				for (int l=0;l<=n4;++l)memset(f[i][j][k][l],0x3f,sizeof(int)*(n5+1));
	f[0][0][0][0][0]=0;
	//f[i][j][k][l][l1]: already divided by i 2's, j 3's, k p's, l q's, and l1 r's.
	for (int i=0;i<=n1;++i){
		//printf("i=%d\n",i);
		Int y=x;
		for (int j=0;j<=n2;++j){
			Int z=y;
			for (int k=0;k<=n3;++k){
				Int t=z;
				for (int l=0;l<=n4;++l){
					Int t1=t;
					for (int l1=0;l1<=n5;++l1){
						upd(f[i+1][j][k][l][l1],f[i][j][k][l][l1]+int(t1.a[0]%2),from[i+1][j][k][l][l1],0);
						upd(f[i][j+1][k][l][l1],f[i][j][k][l][l1]+int(t1%3),from[i][j+1][k][l][l1],1);
						upd(f[i][j][k+1][l][l1],f[i][j][k][l][l1]+f0[t1%p],from[i][j][k+1][l][l1],2);
						upd(f[i][j][k][l+1][l1],f[i][j][k][l][l1]+f0[t1%q],from[i][j][k][l+1][l1],3);
						upd(f[i][j][k][l][l1+1],f[i][j][k][l][l1]+f0[t1%r],from[i][j][k][l][l1+1],4);
						t1/=r;
					}
					t/=q;
				}
				z/=p;
			}
			y/=3;
		}
		x/=2;
	}
	return f[n1][n2][n3][n4][n5]+2*n1+3*n2+fp*n3+fq*n4+fr*n5;
}
double run_sample(int T=100){
	int t1=clock();
	double s=0;
	for (int i1=1;i1<=T;++i1){
		// set x to be moderately larger than base, so it will only introduce
		// small error, even if we don't restrict the rand value in [0,base).
		Int x=rand_Int(n1*log10(2)+n2*log10(3)+n3*log10(p)+n4*log10(q)+n5*log10(r)+15);
		s+=calc(x,n1,n2,n3,n4,n5);
	}
	s/=T; s/=(n1*log(2)+n2*log(3)+n3*log(p)+n4*log(q)+n5*log(r))/log(3);
	printf("n1=%d n2=%d n3=%d n4=%d n5=%d p=%d q=%d r=%d T=%d ave=%.6lf\n",n1,n2,n3,n4,n5,p,q,r,T,s);
	printf("time=%d\n",clock()-t1);
	return s;
}
void run(){
	p=5; fp=5; q=7; fq=6; r=11; fr=8;
	n1=N1; n2=N2; n3=N3; n4=N4; n5=N5;
	vector<double> a;
	for (int i1=1;;++i1){
		int T=1;
		double ans=run_sample(T);
		a.push_back(ans);
		double ave=mean(a),mu=stddev(a);
		printf("--------i1=%d #samples=%d mean=%.6lf stddev=%.6lf--------\n",i1,i1*T,ave,mu);
	}
}
//TODO: enumerate exponents
int heuristic_solve(Int x){
	double r1=1,r3=0.136585,r4=0.078049,r5=0.0243902;
	p=5; fp=5; q=7; fq=6; r=11; fr=8;
	int n=ceil(x.size()/(r1*log10(2)+log10(3)+r3*log10(p)+r4*log10(q)+r5*log10(r)));
	int n1=ceil(n*r1),n2=n,n3=ceil(n*r3),n4=ceil(n*r4),n5=ceil(n*r5);
	printf("%d %d %d %d %d\n",n1,n2,n3,n4,n5);
	return calc(x,n1,n2,n3,n4,n5);
}
